SAML_NS = "urn:oasis:names:tc:SAML:2.0:assertion"
SAMLP_NS = "urn:oasis:names:tc:SAML:2.0:protocol"

# Helper to prefix tag names with namespaces for ElementTree
def saml_tag(tag):
    return f"{{{SAML_NS}}}{tag}"

def samlp_tag(tag):
    return f"{{{SAMLP_NS}}}{tag}"

