@app.route('/saml/acs', methods=['POST'])
def saml_acs():
    if 'SAMLResponse' not in request.form:
        app.logger.error("SAMLResponse parameter missing in POST request.")
        return "SAMLResponse parameter missing", 400

    saml_response_b64 = request.form['SAMLResponse']

    try:
        # SAML responses are typically base64 encoded. They might also be DEFLATE compressed.
        # We'll try to decompress with zlib's raw DEFLATE format (-15 window bits) first.
        # If that fails, assume it's just base64 decoded XML.
        try:
            saml_xml_bytes = zlib.decompress(base64.b64decode(saml_response_b64), -15)
        except zlib.error:
            app.logger.warning("SAMLResponse decompression failed, attempting direct base64 decode. It might not have been compressed or is malformed.")
            saml_xml_bytes = base64.b64decode(saml_response_b64)

        saml_xml = saml_xml_bytes.decode('utf-8')
        app.logger.info(f"Received and decoded SAML XML:\n{saml_xml}")

        # Parse the XML
        root = ET.fromstring(saml_xml)

        # 1. Validate that an Assertion element is present
        # We look for <saml:Assertion> within the response
        assertion_element = root.find(saml_tag('Assertion'))
        if assertion_element is None:
            # Also check if the Assertion might be encrypted (though we don't handle decryption here)
            encrypted_assertion = root.find(f"{{{SAML_NS}}}EncryptedAssertion")
            if encrypted_assertion:
                app.logger.error("SAML Assertion is encrypted, which is not supported by this basic example.")
                return "SAML Assertion is encrypted. This SP does not support encrypted assertions.", 400
            app.logger.error("SAML Assertion not found in the response.")
            return "SAML Assertion not found in the response.", 400

        # --- Basic SAML Attribute Extraction ---

        # Extract NameID (user identifier) from Subject
        name_id_element = assertion_element.find(f"{saml_tag('Subject')}/{saml_tag('NameID')}")
        if name_id_element is None:
            app.logger.error("NameID not found in Assertion Subject.")
            return "NameID not found in Assertion Subject.", 400

        user_name_id = name_id_element.text
        if not user_name_id:
            app.logger.error("NameID value is empty.")
            return "NameID value is empty.", 400

        # Extract user attributes from AttributeStatement
        user_attributes = {}
        attribute_statement = assertion_element.find(saml_tag('AttributeStatement'))
        if attribute_statement is not None:
            for attribute in attribute_statement.findall(saml_tag('Attribute')):
                attr_name = attribute.get('Name')
                if attr_name:
                    attr_values = []
                    # Find all AttributeValue elements for the current attribute
                    for attr_value_element in attribute.findall(saml_tag('AttributeValue')):
                        # SAML attributes can have multiple values or complex types.
                        # For simplicity, we'll take the text content.
                        if attr_value_element.text:
                            attr_values.append(attr_value_element.text.strip())
                    if attr_values:
                        # If there's only one value, store it directly; otherwise, store as a list.
                        user_attributes[attr_name] = attr_values[0] if len(attr_values) == 1 else attr_values
        else:
            app.logger.warning("No AttributeStatement found in the SAML Assertion.")

        # Create user session
        session['user'] = {
            'nameid': user_name_id,
            'attributes': user_attributes
        }
        app.logger.info(f"User '{user_name_id}' logged in with attributes: {user_attributes}")
        return redirect(url_for('index'))

    except ET.ParseError as e:
        app.logger.error(f"SAML XML parsing error: {e}", exc_info=True)
        return "Failed to parse SAML XML. Response might be malformed.", 400
    except Exception as e:
        app.logger.error(f"An unexpected error occurred during SAML processing: {e}", exc_info=True)
        return "An internal server error occurred during SAML processing.", 500

@app.route('/logout')
def logout():
    session.pop('user', None)
    app.logger.info("User logged out.")
    return redirect(url_for('index'))

